// Extrai lista única de produtos pai dos matches da busca.
// A tool recebe tipo+tamanho e a busca trouxe derivações que matcham esse termo.
// Para cada pai único, vamos consultar estoque real.

const input = $input.first().json;
const tipo = $('When Executed by Another Workflow').first().json.tipo || '';
const tamanho = $('When Executed by Another Workflow').first().json.tamanho || '';

const items = input.items || [];

if (items.length === 0) {
  // Retorna um marcador para o próximo nó saber que não há o que consultar.
  return [{ json: { _vazio: true, tipo, tamanho } }];
}

// Agrupa por codigoProduto, guardando o primeiro nome/marca encontrado
const pais = {};
for (const it of items) {
  const codigo = it.codigoProduto;
  if (!codigo) continue;
  if (!pais[codigo]) {
    pais[codigo] = {
      codigoPai: String(codigo),
      nome: it.nomeProduto || '',
      marca: it.nomeMarca || '',
      tipo,
      tamanho
    };
  }
}

// Emite um item por pai único para o HTTP Request seguinte iterar
return Object.values(pais).map(p => ({ json: p }));

// Recebe N itens, um por pai, cada um com estoque completo desse pai.
// Filtra derivações no tamanho pedido com quantidadeDisponivelVenda > 0.
// Gera: (1) link específico por produto, (2) link de categoria filtrada pelo tamanho.

const trigger = $('When Executed by Another Workflow').first().json;
const tipo = (trigger.tipo || '').toLowerCase().trim();
const tamanho = String(trigger.tamanho || '').trim();

// Mapa tamanho → derivacaoItemId (usado no filtro ?derivacao=X do site)
const TAMANHO_ID = {
  '15': 167, '16': 170, '17': 171, '17/18': 110, '18': 172, '19': 109,
  '20': 111, '20/21': 153, '21': 108, '22': 112, '23': 173, '23/24': 81,
  '24': 174, '25': 151, '25/26': 80, '26': 176, '26/27': 152, '27': 175,
  '28': 157, '29': 155, '29/30': 82, '30': 156, '31': 159, '32': 158,
  '32/33': 204, '33': 131, '33/34': 78, '34': 134, '35': 132, '35/36': 87,
  '36': 137, '37': 136, '37/38': 86, '38': 138, '39/40': 89, '41': 161,
  '41/42': 88, '42': 160, '43/44': 114, '44/45': 274, '45/46': 116,
  '46/47': 208, '47/48': 128, 'UN': 84, 'und': 3698
};

// Mapa de tipo → path da categoria no site
const TIPO_PATH = {
  'sandalia': 'sandalia', 'sandália': 'sandalia',
  'chinelo': 'chinelo',
  'tenis': 'tenis-feminino', 'tênis': 'tenis-feminino',
  'bota': 'bota', 'sapatilha': 'sapatilha',
  'tamanco': 'tamanco', 'papete': 'papete',
  'rasteirinha': 'rasteirinha'
};

function pathDoTipo(t) {
  const tl = t.toLowerCase();
  for (const k of Object.keys(TIPO_PATH)) {
    if (tl.includes(k)) return TIPO_PATH[k];
  }
  return ''; // cai na raiz do site
}

function makeSlug(nomeDerivacao) {
  let s = nomeDerivacao.replace(/\s+(\d+(\/\d+)?(\s+un)?|un)\)\s*$/i, ')');
  s = s.replace(/[()]/g, ' ');
  s = s.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  s = s.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  return s;
}

function extrairCor(desc) {
  const parte = desc.split(' - ').slice(1).join(' - ') || desc;
  const m = parte.match(/\(([^)]+)\)/);
  if (!m) return '';
  let cor = m[1];
  cor = cor.replace(/\s+\d+(\/\d+)?(\s+un)?\s*$/i, '').replace(/\s+un\s*$/i, '');
  cor = cor.replace(/^\d+\s+/, '').trim();
  return cor;
}

function matchTamanho(desc, tam) {
  const esc = tam.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const re = new RegExp(`(\\s|\\()${esc}(\\s+un)?\\s*\\)`);
  return re.test(desc);
}

// Monta link de categoria filtrada pelo tamanho
function linkCategoriaFiltrada(tipoInput, tam) {
  const path = pathDoTipo(tipoInput);
  const base = 'https://www.chinelarialeilaneneves.com.br/' + path;
  const id = TAMANHO_ID[tam];
  if (!id) return base;
  return `${base}?derivacao=${id}`;
}

const items = $input.all();
const grupos = {};

for (const it of items) {
  const payload = it.json;
  if (payload._vazio) continue;

  const estoqueData = Array.isArray(payload.data) ? payload.data : [];
  if (estoqueData.length === 0) continue;

  const primeiroDesc = estoqueData[0].descricaoProduto || '';
  const nomePai = primeiroDesc.split(' - ')[0] || '';

  for (const e of estoqueData) {
    const qtd = e.quantidadeDisponivelVenda || 0;
    const desc = e.descricaoProduto || '';
    if (qtd <= 0) continue;
    if (!matchTamanho(desc, tamanho)) continue;

    const nomeDerivacao = desc.split(' - ').slice(1).join(' - ') || desc;
    const slug = makeSlug(nomeDerivacao);
    const link = `https://www.chinelarialeilaneneves.com.br/${slug}`;

    const cor = extrairCor(desc);
    const chave = `${nomePai}|${cor}`;
    if (!grupos[chave]) {
      grupos[chave] = { nome: nomePai, cor, quantidade: qtd, sku: e.produto, link };
    } else {
      grupos[chave].quantidade += qtd;
    }
  }
}

const resultado = Object.values(grupos).slice(0, 10);
const linkFiltrado = linkCategoriaFiltrada(tipo, tamanho);

if (resultado.length === 0) {
  return [{
    json: {
      encontrados: 0,
      tamanho,
      link_filtrado: linkFiltrado,
      mensagem: `Nenhum produto encontrado no tamanho ${tamanho} com estoque no momento.`
    }
  }];
}

return [{
  json: {
    encontrados: resultado.length,
    tamanho,
    link_filtrado: linkFiltrado,
    produtos: resultado
  }
}];
